Extrae los datos de las revisiones de vinos de España y Portugal, únelos con la tabla de producción para el año 2019, y guárdalos en un data.frame llamado vinos_ib.








TipSolución






vinos_ib &lt;- winetbl |&gt;
  filter(country %in% c("Spain", "Portugal")) |&gt;
  left_join(
    prodbl |&gt; filter(anio == 2019),
    by = c("country" = "pais")
  ) |&gt;
  collect()










PrecauciónEjercicio



Usando la tabla dos_espana, obtén la puntuación media por comunidad autónoma para los vinos españoles. Ordena el resultado de mayor a menor puntuación.








TipSolución






dostbl &lt;- tbl(con, "dos_espana")

winetbl |&gt;
  filter(country == "Spain") |&gt;
  left_join(dostbl, by = c("region_1" = "do")) |&gt;
  filter(!is.na(comunidad)) |&gt;
  group_by(comunidad) |&gt;
  summarise(
    n_resenas    = n(),
    puntos_medio = mean(points, na.rm = TRUE),
    precio_medio = mean(price,  na.rm = TRUE),
    .groups      = "drop"
  ) |&gt;
  arrange(desc(puntos_medio)) |&gt;
  collect()

Código final con el análisis sin dar error.
library(shiny)
library(bslib)
library(readr)
library(ggplot2)
library(dplyr)
library(DT)
library(broom)
library(report)
library(giscoR)
giscoR::gisco_get_countries()

tasting &lt;- read_rds("datos/clean/tasting.rds")

ui &lt;- page_navbar(
  theme = bs_theme(bootswatch = "solar"),
  title = "El vino y yo",
  sidebar = sidebar(title = "Menú lateral",
                    selectizeInput("ipais",
                                   label = "País",
                                   choices = unique(tasting$fct_country)),
                    checkboxInput("ilog", label = "Logaritmo"),
                    selectizeInput("icolormodelo",
                                   label = "Color puntos",
                                   choices = c("fct_country",
                                               "fct_variety"))),
  nav_panel("Exploración", 
            "Análisis por país",
            plotOutput("ohistprecio")),
  nav_panel("Modelo de precio", 
            "Estimación del precio",
            navset_card_underline(
              title = "Modelización",
              nav_panel("Gráfico de dispersión",
                        plotOutput("odisp")),
              nav_panel("Coeficientes",
                        dataTableOutput("ocoeficientes")),
              nav_panel("Análisis",
                        uiOutput("oanalisis"))
            ))

)

server &lt;- function(input, output) {
  output$ohistprecio &lt;- renderPlot({
    tasting |&gt; 
      filter(fct_country == input$ipais) |&gt; 
      ggplot(aes_string(x = ifelse(input$ilog, "logPrice", "price"))) +
      geom_histogram(bins = 15, col = "white", fill = "orange")
  })
  output$odisp &lt;- renderPlot({
    tasting |&gt;
      ggplot(aes_string(y = ifelse(input$ilog, "logPrice", "price"),
                        x = "points",
                        col = input$icolormodelo)) +
      geom_point()
  })
  output$ocoeficientes &lt;- renderDT({
    if(input$ilog){
      f &lt;- as.formula(paste0("logPrice ~ points + fct_country + fct_variety"))
    } else{
      f &lt;- as.formula(paste0("price ~ points + fct_country + fct_variety"))
    }
    modelo &lt;- lm(f, data = tasting)
    datatable(modelo |&gt; tidy()) |&gt; 
      formatRound(columns = 2:5, digits = 4)
  })

  output$oanalisis &lt;- renderText({
    modelo &lt;- lm(logPrice ~ points, data = tasting)
    report(modelo) |&gt; 
      markdown()
  })
}

shinyApp(ui, server)

Evoluciones
Añadimos un input para mostrar el precio en escala logarítmica. La transformación se aplica después de collect(), en R, no en la base de datos.
library(shiny)
library(bslib)
library(DBI)
library(RSQLite)
library(dbplyr)
library(dplyr)
library(ggplot2)

con  &lt;- dbConnect(SQLite(), dbname = "data/wine.db", flags = SQLITE_RO)
wine &lt;- tbl(con, "tasting")

raw &lt;- wine |&gt; select(country, variety) |&gt; collect()

top_countries &lt;- names(sort(table(raw$country), decreasing = TRUE))[1:20]
top_varieties &lt;- names(sort(table(raw$variety), decreasing = TRUE))[1:20]

lump &lt;- function(x, top) if_else(x %in% top, x, "Other")

ui &lt;- page_navbar(
  title = "El vino y yo",
  sidebar = sidebar(title = "Menú lateral",
                    selectizeInput("ipais",
                                   label = "País",
                                   choices = c(sort(top_countries), "Other")),
                    checkboxInput("ilog", label = "Logaritmo")),
  nav_panel("Exploración",
            "Análisis por país",
            plotOutput("ohistprecio")),
  nav_panel("Modelo de precio", "Estimación del precio")
)

server &lt;- function(input, output) {
  output$ohistprecio &lt;- renderPlot({
    q &lt;- if (input$ipais == "Other") {
      wine |&gt; filter(!country %in% !!top_countries)
    } else {
      wine |&gt; filter(country == !!input$ipais)
    }
    q |&gt; select(price) |&gt; collect() |&gt;
      mutate(y = if (input$ilog) log(price, 10) else price) |&gt;
      ggplot(aes(x = y)) +
      geom_histogram(bins = 15, col = "white", fill = "orange") +
      labs(x = if (input$ilog) "log10(precio)" else "precio")
  })
}

