Extra: Incluir un mapa
Añadimos una nueva pestaña con un mapa interactivo {leaflet} que muestra el precio mediano por país, leyendo los datos directamente de la base de datos.
Los paquetes necesarios son {sf} para geometrías, {giscoR} para las fronteras mundiales y {leaflet} para el mapa interactivo.
Los nombres de país del dataset de catas no coinciden exactamente con los de {giscoR}, así que creamos un vector de reasignación (country_recode) antes de hacer el join.
El agregado por país (group_by + summarise) se ejecuta en la base de datos antes de collect(), de modo que solo se transfieren a R los ~45 países con datos, no las 130.000 filas.
library(shiny)
library(bslib)
library(DBI)
library(RSQLite)
library(dbplyr)
library(dplyr)
library(ggplot2)
library(DT)
library(broom)
library(tidyr)
library(sf)
library(giscoR)
library(leaflet)

con  &lt;- dbConnect(SQLite(), dbname = "data/wine.db", flags = SQLITE_RO)
# Alternatively, connect to the hosted PostgreSQL database:
# library(RPostgres)
# con &lt;- dbConnect(RPostgres::Postgres(),
#                  host     = "dslabapps.es",
#                  port     = 5499,
#                  dbname   = "wine",
#                  user     = "readonly_user",
#                  password = "wine_readonly")
wine &lt;- tbl(con, "tasting")

raw &lt;- wine |&gt; select(country, variety) |&gt; collect()

top_countries &lt;- names(sort(table(raw$country), decreasing = TRUE))[1:20]
top_varieties &lt;- names(sort(table(raw$variety), decreasing = TRUE))[1:20]

lump &lt;- function(x, top) if_else(x %in% top, x, "Other")

# Nombres del dataset -&gt; nombres de giscoR
country_recode &lt;- c(
  "Czech Republic" = "Czechia",
  "England"        = "United Kingdom",
  "Macedonia"      = "North Macedonia",
  "Turkey"         = "Türkiye",
  "US"             = "United States"
)

# Agregado en la base de datos + join con geometrías (una sola vez al arrancar)
countries_geo &lt;- gisco_get_countries()

geo_data &lt;- wine |&gt;
  group_by(country) |&gt;
  summarise(
    med_price  = median(price, na.rm = TRUE),
    avg_points = mean(points,  na.rm = TRUE),
    n_resenas  = n(),
    .groups    = "drop"
  ) |&gt;
  collect() |&gt;
  mutate(country_geo = recode(country, !!!country_recode)) |&gt;
  right_join(countries_geo |&gt; select(NAME_ENGL, geometry),
             by = c("country_geo" = "NAME_ENGL")) |&gt;
  st_as_sf()

ui &lt;- page_navbar(
  theme = bs_theme(bootswatch = "cosmo"),
  title = "El vino y yo",
  sidebar = sidebar(title = "Menú lateral",
                    selectizeInput("ipais",
                                   label = "País",
                                   choices = c(sort(top_countries), "Other")),
                    checkboxInput("ilog", label = "Logaritmo"),
                    selectizeInput("icolormodelo",
                                   label = "Color puntos",
                                   choices = c("fct_country", "fct_variety"))),
  nav_panel("Exploración",
            "Análisis por país",
            plotOutput("ohistprecio")),
  nav_panel("Mapa",
            leafletOutput("omapa", height = "600px")),
  nav_panel("Modelo de precio",
            "Estimación del precio",
            navset_card_underline(
              title = "Modelización",
              nav_panel("Gráfico de dispersión",
                        plotOutput("odisp")),
              nav_panel("Coeficientes",
                        dataTableOutput("ocoeficientes")),
              nav_panel("Análisis",
                        verbatimTextOutput("oanalisis"))))
)

server &lt;- function(input, output) {

  modelo &lt;- reactive({
    wine |&gt;
      select(price, points, country, variety) |&gt;
      collect() |&gt;
      mutate(
        y           = if (input$ilog) log(price, 10) else price,
        fct_country = factor(lump(country, top_countries)),
        fct_variety = factor(lump(variety, top_varieties))
      ) |&gt;
      lm(y ~ points + fct_country + fct_variety, data = _)
  })

  output$ohistprecio &lt;- renderPlot({
    q &lt;- if (input$ipais == "Other") {
      wine |&gt; filter(!country %in% !!top_countries)
    } else {
      wine |&gt; filter(country == !!input$ipais)
    }
    q |&gt; select(price) |&gt; collect() |&gt;
      mutate(y = if (input$ilog) log(price, 10) else price) |&gt;
      ggplot(aes(x = y)) +
      geom_histogram(bins = 15, col = "white", fill = "orange") +
      labs(x = if (input$ilog) "log10(precio)" else "precio")
  })

  output$omapa &lt;- renderLeaflet({
    pal &lt;- colorBin(
      "YlOrRd",
      domain   = geo_data$med_price,
      bins     = quantile(geo_data$med_price, probs = c(0, 0.25, 0.5, 0.75, 1), na.rm = TRUE),
      na.color = "#cccccc"
    )

    geo_data |&gt;
      leaflet() |&gt;
      addTiles() |&gt;
      addPolygons(
        fillColor   = ~pal(med_price),
        weight      = 1,
        opacity     = 1,
        color       = "white",
        dashArray   = "3",
        fillOpacity = 0.7,
        label       = ~paste0(country, ": $", round(med_price, 1),
                               " | ", round(avg_points, 1), " pts",
                               " (", n_resenas, " reseñas)")
      ) |&gt;
      addLegend(
        pal      = pal,
        values   = ~med_price,
        title    = "Precio mediano ($)",
        position = "bottomright"
      )
  })

  output$odisp &lt;- renderPlot({
    col_raw &lt;- sub("fct_", "", input$icolormodelo)
    wine |&gt;
      select(points, price, all_of(col_raw)) |&gt;
      collect() |&gt;
      rename(color = 3) |&gt;
      mutate(
        y     = if (input$ilog) log(price, 10) else price,
        color = lump(color, if (col_raw == "country") top_countries else top_varieties)
      ) |&gt;
      ggplot(aes(x = points, y = y, col = color)) +
      geom_point(alpha = 0.3) +
      labs(y = if (input$ilog) "log10(precio)" else "precio",
           col = input$icolormodelo)
  })

  output$ocoeficientes &lt;- renderDT({
    datatable(tidy(modelo())) |&gt;
      formatRound(columns = 2:5, digits = 4)
  })

  output$oanalisis &lt;- renderPrint({
    summary(modelo())
  })
}

shinyApp(ui, server)

Extra: Interpretación con IA
Podemos añadir un botón en la pestaña Análisis que envíe el resumen del modelo a un LLM vía OpenRouter y muestre una interpretación en lenguaje sencillo. No hay conversación, es una sola llamada: le mandamos el output de summary() y el modelo responde.
Para que funcione, necesitas una clave de API en .Renviron:
OPENROUTER_API_KEY=sk-or-...
#| eval: false
library(shiny)
library(bslib)
library(DBI)
library(RSQLite)
library(dbplyr)
library(dplyr)
library(httr2)
library(ggplot2)
library(DT)
library(broom)
library(tidyr)
library(sf)
library(giscoR)
library(leaflet)

con  &lt;- dbConnect(SQLite(), dbname = "data/wine.db", flags = SQLITE_RO)
# Alternatively, connect to the hosted PostgreSQL database:
# library(RPostgres)
# con &lt;- dbConnect(RPostgres::Postgres(),
#                  host     = "dslabapps.es",
#                  port     = 5499,
#                  dbname   = "wine",
#                  user     = "readonly_user",
#                  password = "wine_readonly")
wine &lt;- tbl(con, "tasting")

raw &lt;- wine |&gt; select(country, variety) |&gt; collect()

top_countries &lt;- names(sort(table(raw$country), decreasing = TRUE))[1:20]
top_varieties &lt;- names(sort(table(raw$variety), decreasing = TRUE))[1:20]

lump &lt;- function(x, top) if_else(x %in% top, x, "Other")

country_recode &lt;- c(
  "Czech Republic" = "Czechia",
  "England"        = "United Kingdom",
  "Macedonia"      = "North Macedonia",
  "Turkey"         = "Türkiye",
  "US"             = "United States"
)

countries_geo &lt;- gisco_get_countries()

geo_data &lt;- wine |&gt;
  group_by(country) |&gt;
  summarise(
    med_price  = median(price, na.rm = TRUE),
    avg_points = mean(points,  na.rm = TRUE),
    n_resenas  = n(),
    .groups    = "drop"
  ) |&gt;
  collect() |&gt;
  mutate(country_geo = recode(country, !!!country_recode)) |&gt;
  right_join(countries_geo |&gt; select(NAME_ENGL, geometry),
             by = c("country_geo" = "NAME_ENGL")) |&gt;
  st_as_sf()

interpretar_modelo &lt;- function(summary_text) {
  api_key &lt;- Sys.getenv("OPENROUTER_API_KEY")
  if (nchar(api_key) == 0) stop("OPENROUTER_API_KEY no configurada en .Renviron")

  request("https://openrouter.ai/api/v1/chat/completions") |&gt;
    req_headers(Authorization = paste("Bearer", api_key),
                `Content-Type` = "application/json") |&gt;
    req_body_json(list(
      model    = "openrouter/free",
      messages = list(
        list(role = "system",
             content = paste(
               "Eres un profesor de estadística. Interpreta el siguiente",
               "resumen de un modelo de regresión lineal en lenguaje sencillo",
               "para estudiantes de máster sin experiencia avanzada en estadística.",
               "Destaca los coeficientes más importantes, el R², y si el modelo",
               "es útil para predecir el precio del vino. Responde en español,",
               "en 3-4 párrafos breves."
             )),
        list(role = "user", content = summary_text)
      )
    )) |&gt;
    req_perform() |&gt;
    resp_body_json(simplifyVector = FALSE) |&gt;
    (`[[`)("choices") |&gt; (`[[`)(1) |&gt; (`[[`)("message") |&gt; (`[[`)("content")
}

ui &lt;- page_navbar(
  theme = bs_theme(bootswatch = "cosmo"),
  title = "El vino y yo",
  sidebar = sidebar(title = "Menú lateral",
                    selectizeInput("ipais",   label = "País",
                                   choices = c(sort(top_countries), "Other")),
                    checkboxInput("ilog",     label = "Logaritmo"),
                    selectizeInput("icolormodelo", label = "Color puntos",
                                   choices = c("fct_country", "fct_variety"))),
  nav_panel("Exploración",
            plotOutput("ohistprecio")),
  nav_panel("Mapa",
            leafletOutput("omapa", height = "600px")),
  nav_panel("Modelo de precio",
            navset_card_underline(
              title = "Modelización",
              nav_panel("Gráfico de dispersión", plotOutput("odisp")),
              nav_panel("Coeficientes",          dataTableOutput("ocoeficientes")),
              nav_panel("Análisis",
                        verbatimTextOutput("oanalisis"),
                        hr(),
                        actionButton("ibtnia", "Interpretar con IA",
                                     icon = icon("robot")),
                        uiOutput("ointerpretacion"))))
)

server &lt;- function(input, output) {

  modelo &lt;- reactive({
    wine |&gt;
      select(price, points, country, variety) |&gt;
      collect() |&gt;
      mutate(
        y           = if (input$ilog) log(price, 10) else price,
        fct_country = factor(lump(country, top_countries)),
        fct_variety = factor(lump(variety, top_varieties))
      ) |&gt;
      lm(y ~ points + fct_country + fct_variety, data = _)
  })

  output$ohistprecio &lt;- renderPlot({
    q &lt;- if (input$ipais == "Other") {
      wine |&gt; filter(!country %in% !!top_countries)
    } else {
      wine |&gt; filter(country == !!input$ipais)
    }
    q |&gt; select(price) |&gt; collect() |&gt;
      mutate(y = if (input$ilog) log(price, 10) else price) |&gt;
      ggplot(aes(x = y)) +
      geom_histogram(bins = 15, col = "white", fill = "orange") +
      labs(x = if (input$ilog) "log10(precio)" else "precio")
  })

  output$omapa &lt;- renderLeaflet({
    pal &lt;- colorBin("YlOrRd",
                    domain   = geo_data$med_price,
                    bins     = quantile(geo_data$med_price,
                                        probs = c(0, 0.25, 0.5, 0.75, 1),
                                        na.rm = TRUE),
                    na.color = "#cccccc")
    geo_data |&gt;
      leaflet() |&gt;
      addTiles() |&gt;
      addPolygons(fillColor = ~pal(med_price), weight = 1, opacity = 1,
                  color = "white", dashArray = "3", fillOpacity = 0.7,
                  label = ~paste0(country, ": $", round(med_price, 1),
                                  " | ", round(avg_points, 1), " pts",
                                  " (", n_resenas, " reseñas)")) |&gt;
      addLegend(pal = pal, values = ~med_price,
                title = "Precio mediano ($)", position = "bottomright")
  })

  output$odisp &lt;- renderPlot({
    col_raw &lt;- sub("fct_", "", input$icolormodelo)
    wine |&gt;
      select(points, price, all_of(col_raw)) |&gt;
      collect() |&gt;
      rename(color = 3) |&gt;
      mutate(y     = if (input$ilog) log(price, 10) else price,
             color = lump(color, if (col_raw == "country") top_countries
                                 else top_varieties)) |&gt;
      ggplot(aes(x = points, y = y, col = color)) +
      geom_point(alpha = 0.3) +
      labs(y = if (input$ilog) "log10(precio)" else "precio",
           col = input$icolormodelo)
  })

  output$ocoeficientes &lt;- renderDT({
    datatable(tidy(modelo())) |&gt; formatRound(columns = 2:5, digits = 4)
  })

  output$oanalisis &lt;- renderPrint({
    summary(modelo())
  })

  interpretacion &lt;- eventReactive(input$ibtnia, {
    summary_text &lt;- paste(capture.output(summary(modelo())), collapse = "\n")
    withProgress(message = "Consultando IA...", interpretar_modelo(summary_text))
  })

  output$ointerpretacion &lt;- renderUI({
    req(interpretacion())
    div(style = "margin-top:1rem; padding:1rem; background:#f8f9fa; border-radius:6px;",
        h5("Interpretación"),
        p(interpretacion()))
  })
}

shinyApp(ui, server)
